import './results.css';
// Here we are passing in the object we want as props and deconstructing it. 
// We do need an Id for each row but that is in the calling code where we are .Map the array
// <ResultsRow key={fixture.Id} {fixture=h}
const ResultsRow = ({fixture} : any) => {
    
    let resultClassToAdd = "";
    switch(fixture.result)
    {
        case "W":
            resultClassToAdd = "table-success";
            break;
        case "D":
            resultClassToAdd = "table-secondary";
            break;
        case "L":
            resultClassToAdd = "table-danger";
            break;

    }    
    
    return(             
        <tr>
            <td>{fixture.date}</td>
            <td className={resultClassToAdd}>{fixture.result}</td>
            <td>{fixture.location}</td>                        
            <td className={fixture.homeTeam === "Tigers"  ? "tigersCell" : ""}>{fixture.homeTeam}</td>
            <td>{fixture.homeScore}</td>                        
            <td>{fixture.awayScore}</td>
            <td className={fixture.awayTeam === "Tigers"  ? "tigersCell" : ""}>{fixture.awayTeam}</td>            
            <td>{fixture.pts}</td>
        </tr>
    )
}               
export default ResultsRow;
